{
    "level": "A1–B1",
    "intro": "In this topic you will learn <strong>all main types of pronouns</strong> in the English language and their rules usage.",
    "rules": [
        {
            "label": "Personal",
            "color": "emerald",
            "text": "<strong>Personal pronouns</strong> - who acts:",
            "example": "I work. She reads. They play."
        },
        {
            "label": "Possessive",
            "color": "blue",
            "text": "<strong>Possessive forms</strong> - whose is it:",
            "example": "my book, mine, his, hers"
        },
        {
            "label": "Reflexive",
            "color": "amber",
            "text": "<strong>Reflexive pronouns</strong> - action on self:",
            "example": "I did it myself. She taught herself."
        }
    ]
}

{
    "title": "1. Types of pronouns",
    "intro": "There are several main types of pronouns in the English language:",
    "items": [
        {
            "label": "Personal",
            "title": "Personal",
            "subtitle": "I, you, he, she, it, we, they — who does or receives action"
        },
        {
            "label": "Possessive",
            "title": "Possessive",
            "subtitle": "my/mine, your/yours, his, her/hers — whose is it"
        },
        {
            "label": "Reflexive",
            "title": "Reverse",
            "subtitle": "myself, yourself, himself, herself — action on self"
        },
        {
            "label": "Demonstrative",
            "title": "Indicative",
            "subtitle": "this, that, these, those — indicate objects"
        },
        {
            "label": "Indefinite",
            "title": "Undefined",
            "subtitle": "someone, anybody, nothing — indefinite persons/things"
        },
        {
            "label": "Relative",
            "title": "Relative",
            "subtitle": "who, which, that - connect the parts of the sentence"
        }
    ]
}

{
    "title": "2. Personal Pronouns)",
    "sections": [
        {
            "label": "Subject Pronouns — Subject",
            "color": "emerald",
            "description": "Used as the <strong>subject</strong> of a sentence (who performs the action).",
            "examples": [
                {
                    "en": "I work every day.",
                    "ua": "I work every day."
                },
                {
                    "en": "You are smart.",
                    "ua": "You are smart."
                },
                {
                    "en": "He reads books.",
                    "ua": "He reads books."
                },
                {
                    "en": "She likes music.",
                    "ua": "She likes music."
                },
                {
                    "en": "It is a cat. cat.",
                    "ua": "Це кіт."
                },
                {
                    "en": "We are friends.",
                    "ua": "We are friends."
                },
                {
                    "en": "They play football.",
                    "ua": "They play football."
                }
            ]
        },
        {
            "label": "Object Pronouns - Object",
            "color": "sky",
            "description": "Used as <strong>appendix</strong> (who/what gets the action).",
            "examples": [
                {
                    "en": "Call me later.",
                    "ua": "Call me later."
                },
                {
                    "en": "I see you.",
                    "ua": "I see you."
                },
                {
                    "en": "She loves him.",
                    "ua": "She loves him him."
                },
                {
                    "en": "I know her.",
                    "ua": "I know her."
                },
                {
                    "en": "Give it to me.",
                    "ua": "Give it to me."
                },
                {
                    "en": "They invited us.",
                    "ua": "They invited us."
                },
                {
                    "en": "I like them.",
                    "ua": "I like them."
                }
            ]
        },
        {
            "label": "Table of personal pronouns",
            "color": "purple",
            "description": "Complete table of subject and object pronouns:",
            "examples": [
                {
                    "en": "I → me",
                    "ua": "I → me"
                },
                {
                    "en": "you → you",
                    "ua": "you → you"
                },
                {
                    "en": "he → him",
                    "ua": "he → his"
                },
                {
                    "en": "she → her",
                    "ua": "she → her"
                },
                {
                    "en": "it → it",
                    "ua": "it → his/her"
                },
                {
                    "en": "we → us",
                    "ua": "we → us"
                },
                {
                    "en": "they → them",
                    "ua": "they → their"
                }
            ],
            "note": "📌 Subject = subject (who acts), Object = appendix (whom/what)."
        }
    ]
}

{
    "title": "3. Possessive Forms (Possessive Forms) new.",
    "sections": [
        {
            "label": "Possessive Adjectives — Присвійні прикметники",
            "color": "blue",
            "description": "Стоять <strong>перед іменником</strong> і показують приналежність.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "Це моя книга."
                },
                {
                    "en": "Your car is new.",
                    "ua": "Your car is new."
                },
                {
                    "en": "His name is John.",
                    "ua": "His name is John."
                },
                {
                    "en": "Her sister is a doctor.",
                    "ua": "Her sister is a doctor."
                },
                {
                    "en": "Its color is blue.",
                    "ua": "His color is blue."
                },
                {
                    "en": "Our house is big.",
                    "ua": "Our house is big."
                },
                {
                    "en": "Their dog is cute.",
                    "ua": "They are cute. by a noun!"
                }
            ],
            "note": "Завжди перед іменником!"
        },
        {
            "label": "Possessive Pronouns - Possessive pronouns",
            "color": "sky",
            "description": "<strong>Replace</strong> a noun (stand instead of it).",
            "examples": [
                {
                    "en": "This book is mine.",
                    "ua": "This book is mine."
                },
                {
                    "en": "The car is yours.",
                    "ua": "The car is yours."
                },
                {
                    "en": "That pen is his.",
                    "ua": "The bag is hers."
                },
                {
                    "en": "The bag is hers.",
                    "ua": "The house is ours."
                },
                {
                    "en": "The house is ours.",
                    "ua": "Our house."
                },
                {
                    "en": "Those keys are theirs.",
                    "ua": "Ті ключі їхні."
                }
            ],
            "note": "Стоять самостійно, без іменника!"
        },
        {
            "label": "Важливо!",
            "color": "amber",
            "description": "Не плутай <strong>its</strong> (присвійне) та <strong>it's</strong> (скорочення).",
            "examples": [
                {
                    "en": "Its color is red. (possessive)",
                    "ua": "Its color is red."
                },
                {
                    "en": "It's a cat. (it is)",
                    "ua": "This is a cat."
                }
            ],
            "note": "📌 Its = possessive, It's = contraction of It is."
        }
    ]
}

{
    "title": "4. Reflexive Pronouns",
    "sections": [
        {
            "label": "Reflexive pronoun forms",
            "color": "purple",
            "description": "End in <strong>-self</strong> (singular) or <strong>-selves</strong> (plural).",
            "examples": [
                {
                    "en": "I → myself",
                    "ua": "I → myself (self)"
                },
                {
                    "en": "you → yourself / yourselves",
                    "ua": "you → self"
                },
                {
                    "en": "he → himself",
                    "ua": "he → himself (himself)"
                },
                {
                    "en": "she → herself",
                    "ua": "she → herself (herself)"
                },
                {
                    "en": "it → itself",
                    "ua": "it → itself"
                },
                {
                    "en": "we → ourselves",
                    "ua": "we → ourselves"
                },
                {
                    "en": "they → themselves",
                    "ua": "they → themselves (themselves)"
                }
            ]
        },
        {
            "label": "When to use",
            "color": "emerald",
            "description": "When <strong>subject and object</strong> are the same person.",
            "examples": [
                {
                    "en": "I taught myself English.",
                    "ua": "I taught myself English."
                },
                {
                    "en": "She cut herself.",
                    "ua": "She cut herself (cut herself)."
                },
                {
                    "en": "We enjoyed ourselves.",
                    "ua": "We had a good time (amused ourselves)."
                },
                {
                    "en": "They did it themselves.",
                    "ua": "They did it. himself arrived. Demonstrative Pronouns"
                }
            ]
        },
        {
            "label": "Emphatic use — Підсилення",
            "color": "amber",
            "description": "Для <strong>підсилення</strong>: акцент на тому, хто саме виконав дію.",
            "examples": [
                {
                    "en": "I did it myself.",
                    "ua": "Я зробив це сам (сам, без допомоги)."
                },
                {
                    "en": "The boss himself came.",
                    "ua": "Сам бос прийшов."
                },
                {
                    "en": "She fixed the car herself.",
                    "ua": "Вона сама полагодила машину."
                }
            ],
            "note": "📌 By myself/yourself = самостійно, без допомоги."
        }
    ]
}

{
    "title": "5. Вказівні займенники (Demonstrative Pronouns)",
    "sections": [
        {
            "label": "This / That - Singular",
            "color": "blue",
            "description": "<strong>This</strong> is close, <strong>That</strong> is far.",
            "examples": [
                {
                    "en": "This is my phone.",
                    "ua": "This is my phone. (near)"
                },
                {
                    "en": "That is your car.",
                    "ua": "That is your car. (far)"
                },
                {
                    "en": "I like this.",
                    "ua": "I like this."
                },
                {
                    "en": "What is that?",
                    "ua": "What is that?"
                }
            ]
        },
        {
            "label": "These / Those - Plural",
            "color": "sky",
            "description": "<strong>These</strong> - near, <strong>Those</strong> are far away.",
            "examples": [
                {
                    "en": "These are my books.",
                    "ua": "These are my books. (near)"
                },
                {
                    "en": "Those are your keys.",
                    "ua": "Those are your keys. (far)"
                },
                {
                    "en": "I want these.",
                    "ua": "I want these."
                },
                {
                    "en": "Those are expensive.",
                    "ua": "Those are expensive."
                }
            ],
            "note": "📌 This/That = singular, These/Those = plural."
        }
    ]
}

{
    "title": "6. Other types of pronouns (overview)",
    "sections": [
        {
            "label": "Indefinite Pronouns — Неозначені",
            "color": "purple",
            "description": "Вказують на невизначених осіб або речі.",
            "examples": [
                {
                    "en": "Someone is calling.",
                    "ua": "Someone is calling."
                },
                {
                    "en": "Anybody can do it.",
                    "ua": "Anyone can do it."
                },
                {
                    "en": "Nothing is impossible.",
                    "ua": " impossible."
                },
                {
                    "en": "Everybody knows that.",
                    "ua": "Everybody knows that."
                }
            ]
        },
        {
            "label": "Relative Pronouns — Relative",
            "color": "emerald",
            "description": "Connect parts of a complex sentence.[[[CODX_10]]]The man who called is my boss.",
            "examples": [
                {
                    "en": "The man who called is my boss.",
                    "ua": " — my boss."
                },
                {
                    "en": "The book that I read was great.",
                    "ua": "The book that I read was great."
                },
                {
                    "en": "The car which is red is mine.",
                    "ua": "The car which is red is mine."
                }
            ]
        },
        {
            "label": "Reciprocal Pronouns — Mutual",
            "color": "amber",
            "description": "Indicate mutual action.",
            "examples": [
                {
                    "en": "They love each other.",
                    "ua": "They love each other."
                },
                {
                    "en": "We help one another.",
                    "ua": "We help one another."
                }
            ],
            "note": "📌 Each other = for two, One another = for many."
        }
    ]
}

{
    "title": "7. Comparison table of main pronouns",
    "intro": "Main forms of pronouns:",
    "rows": [
        {
            "en": "Subject",
            "ua": "Subject",
            "note": "I, you, he, she, it, we, they"
        },
        {
            "en": "Object",
            "ua": "Appendix",
            "note": "me, you, him, her, it, us, them"
        },
        {
            "en": "Possessive Adj.",
            "ua": "Possessive Adj.",
            "note": "my, your, his, her, its, our, their"
        },
        {
            "en": "Possessive Pron.",
            "ua": "Possessive Pron.",
            "note": "mine, yours, his, hers, ours, theirs"
        },
        {
            "en": "Reflexive",
            "ua": "Reverse",
            "note": "myself, myself, himself, herself, itself, ourselves, yourselves, themselves"
        }
    ],
    "warning": "📌 Subject = subject, Object = attachment, Possessive = possessive, Reflexive = reflexive."
}

{
    "title": "8. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Confusion of subject and object pronouns.",
            "wrong": "Me and John went to the park.",
            "right": " ✅ <span class="font-mono">John and I went to the park.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Confusion of its and it's.",
            "wrong": "Its a cat. / The dog wagged it's tail.",
            "right": " ✅ <span class="font-mono">It's a cat. / The dog wagged its tail.</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Omission of a reflexive pronoun.",
            "wrong": "I taught English.",
            "right": "​​​​ <span class="font-mono">I taught myself English.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Using a possessive adjective without a noun.",
            "wrong": "This book is my.",
            "right": "​​​​​​ Brief synopsis"
        }
    ]
}

{
    "title": "10. Practice",
    "select_title": "Exercise 1. Choose the correct pronoun",
    "select_intro": "Fill in the blanks with the correct pronoun.",
    "selects": [
        {
            "label": "___ am a student. (I / Me)",
            "prompt": "What is the pronoun?"
        },
        {
            "label": "This book is ___. (my / mine)",
            "prompt": "Which pronoun?"
        },
        {
            "label": "She did it ___. (herself / her)",
            "prompt": "What is the pronoun?"
        },
        {
            "label": "___ is my phone. (This / These)",
            "prompt": "What pronoun?"
        }
    ],
    "options": [
        "I",
        "me",
        "my",
        "mine",
        "myself ",
        "this",
        "these",
        "her",
        "herself"
    ],
    "input_title": "Exercise 2. Fill in the blanks",
    "input_intro": "Write the correct pronoun.",
    "inputs": [
        {
            "before": "___ like music. (me)",
            "after": "→"
        },
        {
            "before": "Give it to ___. (me)",
            "after": "→"
        },
        {
            "before": "This is ___ car. (my)",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correct the mistake",
    "rephrase_intro": "Find and correct the mistake with the pronouns.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "Me and John are friends.",
            "example_target": "John and I are friends."
        },
        {
            "original": "1. Its a beautiful day.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. This book is my.",
            "placeholder": "Correct a mistake"
        }
    ]
}

